const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const express = require('express');
const http = require('http');

class GrpcClient {
  constructor(protoPath, packageName, serviceName, serverAddress) {
    const packageDefinition = protoLoader.loadSync(protoPath, {
      keepCase: true,
      longs: String,
      enums: String,
      defaults: true,
      oneofs: true
    });
    
    const protoDescriptor = grpc.loadPackageDefinition(packageDefinition);
    const servicePackage = packageName.split('.').reduce((obj, key) => obj[key], protoDescriptor);
    
    this.client = new servicePackage[serviceName](
      serverAddress,
      grpc.credentials.createInsecure()
    );
    
    this.serviceName = serviceName;
  }

  createMetadataFromHeaders(headers, forwardHeaders = []) {
    const metadata = new grpc.Metadata();
    
    const defaultForwardHeaders = [
      'user-agent',
      'x-forwarded-for',
      'x-forwarded-host',
      'x-forwarded-proto',
      'x-real-ip',
      'authorization',
      'x-request-id',
      'x-correlation-id',
      'accept-language',
      'content-type'
    ];
    
    const headersToForward = [...new Set([...defaultForwardHeaders, ...forwardHeaders])];
    
    Object.keys(headers).forEach(key => {
      const lowerKey = key.toLowerCase();
      
      if (headersToForward.includes(lowerKey) || lowerKey.startsWith('x-')) {
        const value = headers[key];
        if (value) {
          metadata.add(lowerKey, value);
        }
      }
    });
    
    return metadata;
  }

  call(method, request, headers = {}, customHeaders = []) {
    return new Promise((resolve, reject) => {
      const metadata = this.createMetadataFromHeaders(headers, customHeaders);
      
      if (!this.client[method]) {
        return reject(new Error(`Method ${method} not found on service ${this.serviceName}`));
      }
      
      this.client[method](request, metadata, (error, response) => {
        if (error) {
          reject(error);
        } else {
          resolve(response);
        }
      });
    });
  }

  streamCall(method, request, headers = {}, customHeaders = []) {
    const metadata = this.createMetadataFromHeaders(headers, customHeaders);
    
    if (!this.client[method]) {
      throw new Error(`Method ${method} not found on service ${this.serviceName}`);
    }
    
    return this.client[method](request, metadata);
  }
}

class HttpToGrpcGateway {
  constructor() {
    this.app = express();
    this.grpcClients = new Map();
    this.app.use(express.json());
    this.app.use(express.urlencoded({ extended: true }));
  }

  registerGrpcService(name, protoPath, packageName, serviceName, serverAddress) {
    const client = new GrpcClient(protoPath, packageName, serviceName, serverAddress);
    this.grpcClients.set(name, client);
    return this;
  }

  addRoute(httpMethod, path, serviceName, grpcMethod, requestMapper = null, customHeaders = []) {
    const handler = async (req, res) => {
      try {
        const client = this.grpcClients.get(serviceName);
        
        if (!client) {
          return res.status(500).json({ error: `Service ${serviceName} not found` });
        }

        let grpcRequest = req.body;
        
        if (requestMapper && typeof requestMapper === 'function') {
          grpcRequest = requestMapper(req);
        } else if (httpMethod.toLowerCase() === 'get') {
          grpcRequest = { ...req.query, ...req.params };
        } else {
          grpcRequest = { ...req.body, ...req.params };
        }

        const response = await client.call(grpcMethod, grpcRequest, req.headers, customHeaders);
        res.json(response);
        
      } catch (error) {
        console.error('gRPC Error:', error);
        
        const statusCode = this.mapGrpcStatusToHttp(error.code);
        res.status(statusCode).json({
          error: error.message,
          code: error.code,
          details: error.details
        });
      }
    };

    this.app[httpMethod.toLowerCase()](path, handler);
    return this;
  }

  mapGrpcStatusToHttp(grpcCode) {
    const mapping = {
      [grpc.status.OK]: 200,
      [grpc.status.CANCELLED]: 499,
      [grpc.status.UNKNOWN]: 500,
      [grpc.status.INVALID_ARGUMENT]: 400,
      [grpc.status.DEADLINE_EXCEEDED]: 504,
      [grpc.status.NOT_FOUND]: 404,
      [grpc.status.ALREADY_EXISTS]: 409,
      [grpc.status.PERMISSION_DENIED]: 403,
      [grpc.status.RESOURCE_EXHAUSTED]: 429,
      [grpc.status.FAILED_PRECONDITION]: 400,
      [grpc.status.ABORTED]: 409,
      [grpc.status.OUT_OF_RANGE]: 400,
      [grpc.status.UNIMPLEMENTED]: 501,
      [grpc.status.INTERNAL]: 500,
      [grpc.status.UNAVAILABLE]: 503,
      [grpc.status.DATA_LOSS]: 500,
      [grpc.status.UNAUTHENTICATED]: 401
    };
    
    return mapping[grpcCode] || 500;
  }

  listen(port, callback) {
    this.server = this.app.listen(port, callback);
    return this.server;
  }

  close() {
    if (this.server) {
      this.server.close();
    }
  }
}

const gateway = new HttpToGrpcGateway();

gateway.registerGrpcService(
  'userService',
  './protos/user.proto',
  'user',
  'UserService',
  'localhost:50051'
);

gateway.addRoute('POST', '/api/users', 'userService', 'CreateUser', null, ['x-tenant-id', 'x-api-key']);

gateway.addRoute('GET', '/api/users/:id', 'userService', 'GetUser', (req) => {
  return { id: req.params.id };
}, ['x-tenant-id']);

gateway.addRoute('PUT', '/api/users/:id', 'userService', 'UpdateUser', (req) => {
  return { id: req.params.id, ...req.body };
}, ['x-tenant-id']);

gateway.addRoute('DELETE', '/api/users/:id', 'userService', 'DeleteUser', (req) => {
  return { id: req.params.id };
});

gateway.listen(3000, () => {
  console.log('HTTP to gRPC Gateway listening on port 3000');
});

